<?php
namespace App\Domain\Shops\Admin;use App\Domain\Inventory\ItemClassification;use App\Domain\Media\MediaAssetType;use App\Domain\Shops\ShopAvailabilityService;use App\Domain\Shops\ShopCatalogValidator;use App\Domain\Shops\ShopLocationType;use App\Domain\Shops\ShopOfferCategory;use App\Domain\Shops\ShopOfferVisibility;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use App\Models\Npc;use App\Models\Shop;use App\Models\ShopOffer;use App\Models\Zone;use Carbon\CarbonImmutable;use InvalidArgumentException;
final class ShopAdminReadService{private $media;private $availability;private $validator;private $classification;public function __construct(ShopMediaService $media,ShopAvailabilityService $availability,ShopCatalogValidator $validator,ItemClassification $classification){$this->media=$media;$this->availability=$availability;$this->validator=$validator;$this->classification=$classification;}public function listing(){$page=Shop::withCount('offers')->with(['npc','locations.locatable','mediaAssets'=>function($q){$q->whereIn('asset_type',[MediaAssetType::BANNER,MediaAssetType::BACKGROUND])->where('is_primary',true);}])->orderBy('sort_order')->orderBy('name')->paginate(25);$page->setCollection($page->getCollection()->map(function($shop){return['model'=>$shop,'banner'=>$this->media->presentation($shop,MediaAssetType::BANNER),'locations'=>$shop->locations->map(function($l){return$l->locatable?$l->locatable->name:'—';})->all(),'available'=>$this->availability->isShopVisible($shop,CarbonImmutable::now())];}));return$page;}public function form(Shop $shop){if($shop->exists)$shop->load(['npc','locations.locatable','offers.item.mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::ICON)->where('is_primary',true);},'mediaAssets'=>function($q){$q->whereIn('asset_type',[MediaAssetType::BANNER,MediaAssetType::BACKGROUND])->where('is_primary',true);}]);$offers=$shop->exists?$shop->offers->sortBy(function($o){return sprintf('%010d:%010d',$o->sort_order,$o->id);})->map(function($offer){return['model'=>$offer,'state'=>$this->offerState($offer),'item'=>$this->itemData($offer->item)];})->values():collect();return['shop'=>$shop,'npcs'=>Npc::orderBy('name')->get(),'zones'=>Zone::with('region.world')->orderBy('region_id')->orderBy('name')->get(),'selected_zone_ids'=>$shop->exists?$shop->locations->where('locatable_type',ShopLocationType::ZONE)->pluck('locatable_id')->map(function($id){return(int)$id;})->all():[],'statuses'=>CatalogStatus::values(),'banner'=>$this->media->presentation($shop,MediaAssetType::BANNER),'background'=>$this->media->presentation($shop,MediaAssetType::BACKGROUND),'offers'=>$offers,'offer_categories'=>ShopOfferCategory::values(),'offer_visibilities'=>ShopOfferVisibility::values()];}public function searchItems($term){return Item::with(['mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::ICON)->where('is_primary',true);}])->where('status',CatalogStatus::ACTIVE)->whereIn('item_type',['material','consumable','equipment','dragon_material'])->where(function($q)use($term){$q->where('name','like','%'.$term.'%')->orWhere('code','like','%'.$term.'%');})->orderBy('name')->limit(20)->get()->filter(function($item){try{$this->validator->validateSellableItem($item,ShopOfferCategory::EVENT);return true;}catch(InvalidArgumentException $e){return false;}})->map(function($item){return$this->itemData($item);})->values();}private function itemData(Item $item){$asset=$item->relationLoaded('mediaAssets')?$item->mediaAssets->first():null;return['id'=>(int)$item->id,'name'=>$item->name,'code'=>$item->code,'item_type'=>$item->item_type,'rarity'=>$item->rarity,'classification'=>$this->classification->classify($item),'max_stack'=>(int)$item->max_stack,'equipment_type'=>$item->equipment_type,'required_level'=>(int)$item->required_level,'icon_url'=>$asset?$asset->url():null];}private function offerState(ShopOffer $offer){$now=CarbonImmutable::now();if($offer->visibility!==ShopOfferVisibility::VISIBLE)return'OCULTA';if($offer->status!==CatalogStatus::ACTIVE)return'INACTIVA';if($offer->starts_at&&$now->lt($offer->starts_at))return'FUTURA';if($offer->ends_at&&$now->gte($offer->ends_at))return'FINALIZADA';if($offer->stock_remaining!==null&&(int)$offer->stock_remaining===0)return'AGOTADA';return$this->availability->isOfferPurchasable($offer,$now)?'VISIBLE Y COMPRABLE':'VISIBLE, NO COMPRABLE';}}
